# @static_binary gtsummary (== 1.6.3)
library(tableone) # <--- CAMBIO: Motor estadístico ligero
library(shiny)
library(bslib)
library(shinyjs)
library(dplyr)  
library(readr)    # En lugar de tidyverse
library(tidyr)    # En lugar de tidyverse
library(stringr)  # En lugar de tidyverse
library(readxl)
library(DT)       # <--- CAMBIO: Motor de renderizado web


# 1. CARGAR PIEZAS (Módulos del Frontend)
source("landingfile.R")
source("tablauno.R")
# source("login.R") # Reservado para el modal de Google posterior


# 2. TEMA
tema_clinico <- bs_theme(
  version = 5, 
  bootswatch = "zephyr", 
  base_font = "Montserrat" # Solo el nombre, sin la función
)

# 3. UI
ui <- fluidPage(
  theme = tema_clinico,
  useShinyjs(),

  tags$head(
    tags$link(rel = "stylesheet", href = "https://fonts.googleapis.com/css2?family=Montserrat:wght@400;600;700;800&display=swap"),
    tags$style(HTML("
      /* 1. ELIMINAR BORDES LATERALES EN TODA LA APP */
      .container-fluid { 
        padding: 0 !important; 
        margin: 0 !important; 
        max-width: 100% !important; 
      }

      /* 2. PROTECCIÓN CONTRA COPIADO (Invisible) */
      .apa-sheet {
        user-select: none !important;
        -webkit-user-select: none !important;
        -moz-user-select: none !important;
        -ms-user-select: none !important;
      }

      .apa-sheet table, .apa-sheet img {
        pointer-events: none !important;
      }

      .var-hover-trigger, .tooltip, .tooltip-inner {
        pointer-events: auto !important;
      }
    "))
  ),
  uiOutput("pantalla_actual")
)

# 4. SERVER
server <- function(input, output, session) {

  # Iniciamos en la Fase 1 (Landing / Carga)
  fase <- reactiveVal(1)

  # VARIABLE MAESTRA: Aquí reside la persistencia de los datos
  archivo_compartido <- reactiveVal(NULL) 

  # --- RENDERIZADO DE PANTALLAS ---
  output$pantalla_actual <- renderUI({
    req(fase())
    if (fase() == 1) {
      ui_landingfile
    } else if (fase() == 2) {
      ui_tablauno
    }
  })

  # --- CONEXIÓN DE MÓDULOS ---

  # IMPORTANTE: Pasamos 'fase' y 'archivo_compartido' por referencia.
  # Cualquier cambio hecho dentro de los módulos afectará a estas variables aquí.

  if (exists("server_landingfile")) {
    server_landingfile(input, output, session, fase, archivo_compartido)
  }

  if (exists("server_tablauno")) {
    # El servidor de la tabla uno debe poder cambiar la fase a 1 para 'atrás'
    server_tablauno(input, output, session, fase, archivo_compartido)
  }

  # --- LÓGICA DE LOGIN (MODAL PARA DESCARGA) ---
  # Se activará cuando decidas bloquear la descarga directa
  observeEvent(input$download_word_trigger, {
    showModal(modalDialog(
      title = "Sign in to AuStats",
      div(style = "text-align:center; padding: 10px;",
          icon("google", style="font-size:30px; color:#4285F4;"),
          h4("Export to Word"),
          p("Please log in to download your formatted report."),
          actionButton("google_auth", "Continue with Google", class="btn-primary w-100")
      ),
      easyClose = TRUE, footer = NULL
    ))
  })
}

shinyApp(ui, server)

# ==============================================================================
# PIEZA: Pantalla de Carga (HERO LAYOUT + MODAL DOCUMENTATION CLARO)
# ==============================================================================

library(shiny)
library(bslib)
library(shinyjs)

# --- 1. UI DE LA PIEZA ---
ui_landingfile <- div(
  useShinyjs(), 

  tags$head(
    tags$link(rel = "stylesheet", href = "https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css"),
    tags$link(rel = "preconnect", href = "https://fonts.googleapis.com"),
    tags$link(rel = "preconnect", href = "https://fonts.gstatic.com", crossorigin = NA),
    tags$link(rel = "stylesheet", href = "https://fonts.googleapis.com/css2?family=Montserrat:ital,wght@0,300;0,400;0,500;0,600;0,700;0,800;0,900;1,400;1,800&family=DM+Mono:wght@300;400;500&display=swap"),
    tags$style(HTML("

      /* =============================================
         0. VARIABLES GLOBAL Y RESET
         ============================================= */
      :root {
        --white:      #ffffff;
        --off:        #f8f9fb;
        --off2:       #f0f4f8;
        --border:     #e2e8f0;
        --border2:    #cbd5e1;
        --ink:        #0f172a;
        --ink2:       #1e293b;
        --ink3:       #334155;
        --muted:      #64748b;
        --muted2:     #94a3b8;

        --blue:       #0284c7;
        --blue-dark:  #0369a1;
        --blue-dim:   #e0f2fe;
        --blue-dim2:  #bae6fd;
        --blue-btn:   #007bff;
        --blue-btn-h: #0056b3;

        --green:      #10b981;
        --green-dark: #059669;
        --green-dim:  #d1fae5;
        --green-dim2: #a7f3d0;

        --beta-green: #059669;
        --beta-border:#6ee7b7;

        --shadow-sm:  0 1px 3px rgba(0,0,0,0.06);
        --shadow-md:  0 4px 16px rgba(0,0,0,0.07), 0 2px 6px rgba(0,0,0,0.04);
        --shadow-lg:  0 20px 60px rgba(0,40,100,0.08);
        --shadow-nav: 0 2px 10px rgba(0,0,0,0.03);
      }

      * { box-sizing: border-box; }
      .container-fluid { padding: 0 !important; margin: 0 !important; max-width: 100% !important; overflow-x: hidden; }
      body { background-color: #f0f2f5; font-family: 'Montserrat', sans-serif !important; color: var(--ink); -webkit-font-smoothing: antialiased; overflow: hidden; }

      /* =============================================
         1. NAVBAR PREMIUM
         ============================================= */
      .navbar-fixed-top {
        position: fixed; top: 0; width: 100%; height: 70px;
        background-color: var(--white); border-bottom: 1px solid var(--border2);
        display: flex; align-items: center; padding: 0 28px;
        z-index: 2000; box-shadow: var(--shadow-nav); gap: 0;
      }
      .nav-logo-icon { background: var(--white); color: var(--blue); width: 36px; height: 36px; border-radius: 8px; display: flex; align-items: center; justify-content: center; box-shadow: 0 2px 5px rgba(0,0,0,0.06); font-size: 18px; flex-shrink: 0; }
      .nav-logo-name { font-weight: 800; font-size: 18px; color: var(--ink); letter-spacing: -0.02em; line-height: 1; }
      .nav-logo-sub { font-size: 10px; color: var(--muted); font-weight: 600; text-transform: uppercase; letter-spacing: 0.06em; display: block; margin-top: 2px; }
      .beta-badge { background-color: var(--white); color: var(--beta-green); border: 1px solid var(--beta-border); font-size: 11px; font-weight: 800; padding: 4px 9px; border-radius: 12px; text-transform: uppercase; letter-spacing: 0.5px; box-shadow: 0 1px 2px rgba(0,0,0,0.05); margin-left: 12px; }
      .right-content-wrapper { display: flex; align-items: center; margin-left: auto; height: 100%; gap: 4px; }
      .nav-divider { width: 1px; height: 28px; background: var(--border2); margin: 0 10px; flex-shrink: 0; }

      /* Dropdown */
      .dropdown-wrapper { position: relative; display: flex; align-items: center; height: 100%; margin: 0 2px; }
      .dropdown-trigger { background: transparent; border: none; font-weight: 600; color: var(--muted); font-size: 14px; cursor: pointer; padding: 8px 14px; border-radius: 0; display: flex; align-items: center; gap: 6px; transition: all 0.2s; }
      .dropdown-trigger:hover { color: var(--blue); background: rgba(2,132,199,0.04); }
      .dropdown-trigger i { font-size: 10px; }
      .dropdown-content { display: none; position: absolute; top: 60px; left: 0; background: var(--white); min-width: 240px; box-shadow: 0 10px 30px rgba(0,0,0,0.12); border: 1px solid var(--border); z-index: 10000; padding: 5px; animation: fadeInDrop 0.18s ease; }
      .dropdown-wrapper:hover .dropdown-content { display: block; }
      .dropdown-action-link { padding: 11px 14px !important; text-decoration: none !important; display: flex !important; align-items: center; gap: 10px; color: var(--ink3) !important; font-size: 13px; font-weight: 500; transition: background 0.15s, color 0.15s; cursor: pointer; width: 100%; text-align: left; }
      .dropdown-action-link:hover { background-color: var(--off); color: var(--blue) !important; }
      .dropdown-action-link i { width: 20px; text-align: center; color: var(--muted2); transition: color 0.15s; }
      .dropdown-action-link:hover i { color: var(--blue); }
      @keyframes fadeInDrop { from { opacity: 0; transform: translateY(-6px); } to { opacity: 1; transform: translateY(0); } }

      /* Nav Buttons */
      .nav-link-btn { font-weight: 600; color: var(--muted); padding: 8px 14px; border-radius: 0; text-decoration: none !important; font-size: 14px; transition: all 0.2s; cursor: pointer; border: none; background: transparent; white-space: nowrap; }
      .nav-link-btn:hover { color: var(--blue); background: rgba(2,132,199,0.04); }
      .btn-signin { font-weight: 600; font-size: 13px; color: var(--ink2); background: var(--white); border: 1px solid var(--border2); border-radius: 6px; padding: 8px 18px; cursor: pointer; transition: all 0.15s; white-space: nowrap; display: flex; align-items: center; gap: 6px; }
      .btn-signin:hover { border-color: var(--blue); color: var(--blue); }
      .btn-subscribe { font-weight: 700; font-size: 13px; color: var(--white); background: var(--blue); border: none; border-radius: 6px; padding: 8px 20px; cursor: pointer; transition: all 0.15s; box-shadow: 0 2px 8px rgba(2,132,199,0.25); white-space: nowrap; }
      .btn-subscribe:hover { background: var(--blue-dark); box-shadow: 0 4px 14px rgba(2,132,199,0.35); }

      /* =============================================
         2. SCROLL PRINCIPAL Y HERO
         ============================================= */
      .main-scroll-area { height: 100vh; width: 100vw; overflow-y: auto; overflow-x: hidden; background-color: var(--off); scroll-behavior: smooth; }
      .hero-section-landing { min-height: 100vh; width: 100%; display: flex; flex-direction: column; align-items: center; justify-content: center; background: radial-gradient(circle at 15% 20%, rgba(2,132,199,0.12) 0%, transparent 45%), radial-gradient(circle at 85% 80%, rgba(0,210,255,0.10) 0%, transparent 45%); padding-top: 90px; padding-bottom: 60px; }
      .hero-inner { width: 95%; max-width: 1100px; display: grid; grid-template-columns: 1fr 480px; gap: 72px; align-items: center; }

      .hero-kicker { display: inline-flex; align-items: center; gap: 7px; font-size: 10px; font-weight: 700; letter-spacing: 0.12em; text-transform: uppercase; color: var(--blue); background: var(--blue-dim); border: 1px solid var(--blue-dim2); padding: 5px 12px; border-radius: 4px; margin-bottom: 22px; }
      .kicker-dot { width: 6px; height: 6px; background: var(--blue); border-radius: 50%; animation: blink 2s ease-in-out infinite; }
      @keyframes blink { 0%,100%{opacity:1} 50%{opacity:0.25} }

      .hero-title { font-family: 'Montserrat', sans-serif; font-size: clamp(32px, 3.4vw, 48px); font-weight: 800; line-height: 1.12; letter-spacing: -0.03em; color: var(--ink); margin-bottom: 20px; }
      .hero-title em { font-style: italic; font-weight: 800; color: var(--blue); }
      .hero-desc { font-size: 15px; color: var(--muted); line-height: 1.8; font-weight: 400; margin-bottom: 32px; max-width: 480px; }
      .hero-actions { display: flex; align-items: center; gap: 12px; margin-bottom: 36px; flex-wrap: wrap; }
      .btn-hero-primary { font-family: 'Montserrat', sans-serif; font-size: 14px; font-weight: 700; color: var(--white); background: var(--blue-btn); border: none; border-radius: 50px; padding: 13px 32px; cursor: pointer; display: flex; align-items: center; gap: 9px; transition: all 0.18s; box-shadow: 0 4px 15px rgba(0,123,255,0.3); }
      .btn-hero-primary:hover { background: var(--blue-btn-h); box-shadow: 0 6px 20px rgba(0,123,255,0.38); transform: translateY(-1px); }
      .btn-hero-outline { font-family: 'Montserrat', sans-serif; font-size: 14px; font-weight: 600; color: var(--ink2); background: var(--white); border: 1px solid var(--border2); border-radius: 50px; padding: 12px 26px; cursor: pointer; transition: all 0.15s; }
      .btn-hero-outline:hover { border-color: var(--blue); color: var(--blue); }
      .trust-row { display: flex; flex-wrap: wrap; gap: 18px; align-items: center; }
      .trust-item { display: flex; align-items: center; gap: 7px; font-size: 12px; font-weight: 600; color: var(--muted); }
      .trust-item i { font-size: 13px; }
      .trust-item i.green { color: var(--green); }
      .trust-item i.blue  { color: var(--blue); }
      .trust-sep { width: 1px; height: 13px; background: var(--border2); }

      /* =============================================
         3. UPLOAD CARD
         ============================================= */
      .upload-card-wrap { background: var(--white); border-radius: 24px; box-shadow: var(--shadow-lg); padding: 36px 36px 28px; display: flex; flex-direction: column; align-items: center; text-align: center; border: 1px solid var(--border); width: 100%; }
      .upload-card-label { font-size: 10px; font-weight: 800; letter-spacing: 0.14em; text-transform: uppercase; color: var(--muted2); margin-bottom: 20px; width: 100%; text-align: left; display: flex; align-items: center; gap: 10px; }
      .upload-card-label::after { content:''; flex:1; height:1px; background: var(--border); }
      .icon-circle { width: 60px; height: 60px; background-color: #e6f0ff; border-radius: 50%; display: flex; justify-content: center; align-items: center; margin: 0 auto 16px; color: var(--blue-btn); font-size: 26px; transition: all 0.4s; }
      .icon-circle.success { background-color: #d1fae5 !important; color: #10b981 !important; transform: scale(1.08); }
      .upload-main-title { font-weight: 800; font-size: 22px; color: var(--ink); margin-bottom: 4px; }
      .upload-main-sub { font-size: 13px; color: var(--muted); margin-bottom: 20px; }

      .drop-zone { border: 2px dashed #ced4da; border-radius: 18px; background: #f8f9fa; width: 100%; padding: 28px 20px; display: flex; flex-direction: column; align-items: center; justify-content: center; gap: 10px; transition: all 0.25s; margin-bottom: 18px; }
      .drop-zone:hover { border-color: var(--blue-btn); background: #f0f7ff; }
      .drop-zone-label { font-size: 13px; font-weight: 700; text-transform: uppercase; letter-spacing: 1px; color: var(--muted2); margin: 0; }
      .sample-link { color: var(--blue) !important; font-weight: 600; font-size: 13px; text-decoration: none !important; transition: all 0.15s ease; cursor: pointer; }
      .sample-link:hover { color: var(--blue-dark) !important; text-decoration: underline !important; }

      .shiny-input-container { width: 100% !important; margin-bottom: 0 !important; }
      .input-group { display: flex !important; justify-content: center !important; width: 100% !important; }
      .form-control { display: none !important; }
      .btn-select-file { width: 100%; font-family: 'Montserrat', sans-serif; font-size: 14px; font-weight: 700; color: var(--white) !important; background: var(--blue-btn) !important; border: none !important; border-radius: 50px !important; padding: 13px 20px !important; cursor: pointer; display: flex; align-items: center; justify-content: center; gap: 9px; transition: all 0.18s; box-shadow: 0 4px 15px rgba(0,123,255,0.3); }
      .btn-select-file:hover { background: var(--blue-btn-h) !important; box-shadow: 0 6px 20px rgba(0,123,255,0.38) !important; transform: translateY(-1px); }

      .file-success-box { background-color: #f0fdf4; border: 1px solid #bbf7d0; border-radius: 18px; padding: 16px; margin-bottom: 16px; display: flex; flex-direction: column; align-items: center; justify-content: center; width: 100%; }
      .file-success-icon { font-size: 34px; color: #10b981; margin-bottom: 8px; }
      .filename-display { font-size: 13px; font-weight: 600; color: #1e293b; margin: 4px 0 10px 0; word-break: break-all; }
      .upload-area-container { width: 100%; display: flex; flex-direction: column; align-items: center; }
      .result-area-container { width: 100%; display: none; flex-direction: column; align-items: center; }
      .btn-start-analysis { background-color: #10b981 !important; border: none !important; color: white !important; font-weight: 800; border-radius: 50px !important; padding: 13px 50px !important; font-size: 15px !important; box-shadow: 0 4px 15px rgba(16,185,129,0.3); margin-top: 6px !important; width: 100%; display: block; transition: all 0.3s; }
      .btn-start-analysis:hover { background-color: #059669 !important; box-shadow: 0 6px 20px rgba(16,185,129,0.38) !important; transform: translateY(-1px); }
      .btn-start-analysis[disabled] { background-color: #94a3b8 !important; opacity: 0.55; cursor: not-allowed; box-shadow: none; transform: none; }
      .privacy-checkbox-container { display: flex; align-items: flex-start; gap: 10px; margin: 18px 0 14px 0; padding: 12px 15px; background-color: #f8fafc; border-radius: 8px; border: 1px solid #e2e8f0; text-align: left; width: 100%; }
      .privacy-checkbox-container input[type='checkbox'] { margin-top: 3px; cursor: pointer; width: 15px; height: 15px; accent-color: #0284c7; }
      .privacy-checkbox-container label { font-size: 11.5px; color: #475569; margin: 0; font-weight: 500; cursor: pointer; line-height: 1.5; }
      .privacy-link { color: #0284c7; text-decoration: underline; cursor: pointer; }
      .privacy-link:hover { color: #0369a1; }
      .footer-safe { margin-top: 20px; font-size: 11px; font-weight: 500; color: var(--muted2); display: flex; align-items: center; gap: 6px; }
      .footer-safe i { color: #28a745; font-size: 13px; }
      .footer-safe strong { color: var(--ink3); font-weight: 700; }

      /* =============================================
         4. FEATURES SECTION
         ============================================= */
      .features { width: 100%; background: var(--off); padding: 70px 40px 100px; border-top: 1px solid var(--border); }
      .features-inner { max-width: 1100px; margin: 0 auto; }
      .features-header { text-align: center; margin-bottom: 50px; }
      .features-header h2 { font-family: 'Montserrat', sans-serif; font-size: 32px; font-weight: 800; color: var(--ink); margin-bottom: 12px; letter-spacing: -0.02em; }
      .features-header p { font-size: 16px; color: var(--muted); font-weight: 500; }
      .features-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 20px; }
      .feat-card { background: var(--white); border: 1px solid var(--border); border-radius: 16px; padding: 30px 24px; transition: box-shadow 0.2s, border-color 0.2s; text-align: left; display: flex; flex-direction: column; align-items: flex-start; }
      .feat-card:hover { box-shadow: var(--shadow-md); border-color: var(--blue-dim2); }
      .feat-icon { width: 48px; height: 48px; border-radius: 10px; display: flex; align-items: center; justify-content: center; margin-bottom: 20px; font-size: 20px; }
      .fi-blue  { background: var(--blue-dim);  color: var(--blue); }
      .fi-green { background: var(--green-dim); color: var(--green-dark); }
      .fi-slate { background: #f1f5f9; color: #475569; }
      .feat-title { font-weight: 800; font-size: 16px; color: var(--ink); margin-bottom: 10px; }
      .feat-desc { font-size: 14px; color: var(--muted); line-height: 1.65; font-weight: 500; flex-grow: 1; }
      .feat-tag { display: inline-block; margin-top: 24px; font-size: 10px; font-weight: 800; letter-spacing: 0.08em; padding: 6px 12px; border-radius: 6px; text-transform: uppercase; }
      .ft-blue  { color: var(--blue-dark); background: var(--blue-dim); border: 1px solid var(--blue-dim2); }
      .ft-green { color: var(--green-dark); background: var(--green-dim); border: 1px solid var(--green-dim2); }

      /* =============================================
         5. MODALS (GENERAL & CUSTOM)
         ============================================= */
      .modal { z-index: 10050 !important; }
      .modal-backdrop { z-index: 10040 !important; background-color: rgba(10, 25, 47, 0.40) !important; backdrop-filter: blur(5px); }

      /* ESTILOS ESPECÍFICOS PARA EL NUEVO MODAL TIPO DOCUMENTACIÓN (ANALYSIS REPORT) */
      .doc-modal .modal-dialog { max-width: 920px !important; width: 100%; margin: 1.75rem auto; }
      .doc-modal .modal-content {
        background: #ffffff; border-radius: 20px !important; border: 1px solid #dbe6f0 !important;
        box-shadow: 0 20px 64px rgba(0, 40, 100, 0.16), 0 4px 16px rgba(0, 40, 100, 0.08) !important;
        overflow: hidden; display: flex; flex-direction: column; max-height: 90vh; padding: 0 !important;
      }
      .doc-modal .modal-header { display: none !important; }
      .doc-modal .modal-body { padding: 0 !important; display: flex; flex-direction: column; height: 100%; overflow: hidden; }

      /* Hero del Modal Docs - CLARO Y LIMPIO */
      .doc-hero {
        background: radial-gradient(circle at 12% 18%, rgba(2,132,199,0.06) 0%, transparent 45%), linear-gradient(135deg, #f0f9ff 0%, #e0f2fe 100%);
        padding: 28px 38px 24px; position: relative; overflow: hidden; flex-shrink: 0; border-bottom: 1px solid #dbe6f0;
      }
      .doc-hero::before {
        content: ''; position: absolute; bottom: -60px; left: 20%; width: 260px; height: 260px; border-radius: 50%;
        background: radial-gradient(circle, rgba(2,132,199,0.04) 0%, transparent 70%); pointer-events: none;
      }
      .doc-hero-row { display: flex; align-items: flex-start; justify-content: space-between; gap: 16px; }

      .doc-eyebrow {
        display: inline-flex; align-items: center; gap: 7px; font-size: 9px; font-weight: 800; letter-spacing: 0.16em;
        text-transform: uppercase; color: var(--blue-dark); background: rgba(2,132,199,0.06);
        border: 1px solid var(--blue-dim2); padding: 4px 11px; border-radius: 5px; margin-bottom: 13px;
      }
      .doc-title { font-size: 21px; font-weight: 900; color: var(--ink2); letter-spacing: -0.03em; line-height: 1.18; margin-bottom: 7px; }
      .doc-sub { font-size: 11.5px; color: var(--muted); font-weight: 400; margin: 0; }

      .doc-btn-close {
        flex-shrink: 0; margin-top: 2px; width: 29px; height: 29px; background: transparent; border: 1px solid var(--border);
        border-radius: 7px; color: var(--muted2); font-size: 13px; cursor: pointer; display: flex; align-items: center; justify-content: center; transition: all 0.15s;
      }
      .doc-btn-close:hover { background: var(--off); color: var(--blue); border-color: var(--blue-dim2); }

      /* Cuerpo del Modal Docs (Sidebar + Content) */
      .doc-body { display: flex; flex: 1; overflow: hidden; min-height: 0; }
      .doc-sidebar {
        width: 194px; flex-shrink: 0; background: #f4f8fc; border-right: 1px solid #dbe6f0;
        padding: 16px 0; overflow-y: auto;
      }
      .doc-sidebar::-webkit-scrollbar { display: none; }
      .doc-sidebar-label { display: block; font-size: 10px; font-weight: 800; letter-spacing: 0.16em; text-transform: uppercase; color: #94a3b8; padding: 0 16px 10px; }
      .doc-sidebar-item {
        width: 100%; background: none; border: none; padding: 9px 16px; display: flex; align-items: center; gap: 9px;
