# --- 2. LÓGICA DE LA PIEZA ---
server_landingfile <- function(input, output, session, current_fase, global_data) {
  options(shiny.maxRequestSize = 10 * 1024^2)
  archivo_actual <- reactiveVal(NULL)

  shinyjs::disable("btn_empezar")

  # BOTONES HERO (Para que abran archivo o carguen ejemplo)
  observeEvent(input$btn_hero_gen, {
    shinyjs::runjs("$('#archivo_input').click();")
  })

  observeEvent(input$btn_hero_sample, {
    shinyjs::runjs("$('#btn_load_sample').click();")
  })

  # PRIVACIDAD CHECKBOX
  observeEvent(input$check_privacidad, {
    if (isTRUE(input$check_privacidad)) { shinyjs::enable("btn_empezar") } else { shinyjs::disable("btn_empezar") }
  })

  shinyjs::onclick("link_privacidad", {
    showModal(modalDialog(
      title = "Privacy Policy", size = "l", easyClose = TRUE,
      div(style="padding: 20px; font-size: 14px; color: #334155; line-height: 1.6;",
          h4("AuStats Privacy Policy", style="color: #0284c7; font-weight: 800; margin-bottom: 15px;"),
          p(HTML("<b>1. Introduction</b><br>AuStats provides statistical drafting solutions for the life sciences community. We are committed to the highest standards of data privacy, following a 'Privacy-by-Design' philosophy.")),
          p(HTML("<b>2. The Data Privacy Barrier</b><br>Your Excel/CSV files NEVER leave your computer. Our architecture uses local processing in your browser to anonymize data before any interaction with our server.")),
          p(HTML("<b>3. Information We Collect</b><br>Only aggregated statistics (means, p-values, counts) necessary to draft your report are sent to our API.")),
          hr(style = "margin-top: 20px; margin-bottom: 15px; border-top: 1px solid #e2e8f0;"),
          p(HTML(paste0("<b>Effective Date:</b> ", format(Sys.Date(), "%B %d, %Y"))))
      ),
      footer = modalButton("Close")
    ))
  })

  # LÓGICA DE CARGA DE ARCHIVO
  observeEvent(input$archivo_input, {
    file <- input$archivo_input
    req(file) 
    archivo_actual(file$name)
    global_data(file) 
    shinyjs::addClass("status_icon_container", "success")
    shinyjs::runjs("$('#status_icon').removeClass('fa-cloud-arrow-up').addClass('fa-check');")
    shinyjs::hide("upload_zone")
    shinyjs::runjs("$('#file_result_zone').css('display', 'flex');") 
  })

  output$nombre_archivo_mostrado <- renderText({ req(archivo_actual()); archivo_actual() })
  outputOptions(output, "nombre_archivo_mostrado", suspendWhenHidden = FALSE)

  observeEvent(input$btn_eliminar, {
    shinyjs::reset("archivo_input")
    archivo_actual(NULL)
    global_data(NULL) 
    shinyjs::runjs("$('#file_result_zone').css('display', 'none');")
    shinyjs::show("upload_zone")
    shinyjs::removeClass("status_icon_container", "success")
    shinyjs::runjs("$('#status_icon').removeClass('fa-check').addClass('fa-cloud-arrow-up');")
    shinyjs::runjs("document.getElementById('check_privacidad').checked = false;")
    shinyjs::disable("btn_empezar")
  })

  # CARGA DATASET EJEMPLO
  observeEvent(input$btn_load_sample, {
    source("sample_csv.R") 
    data_objeto <- generate_sample_data()
    archivo_actual("clinical_sample_data.csv")

    fake_file_structure <- list(name = "clinical_sample_data.csv", datapath = data_objeto, is_virtual = TRUE)
    global_data(fake_file_structure)

    shinyjs::hide("upload_zone") 
    shinyjs::addClass("status_icon_container", "success")
    shinyjs::runjs("$('#status_icon').removeClass('fa-cloud-arrow-up').addClass('fa-check');")
    shinyjs::runjs("$('#file_result_zone').css('display', 'flex');")

    updateCheckboxInput(session, "check_privacidad", value = TRUE)
    showNotification("Dataset cargado desde memoria (Zero-latency)", type = "message")
  })

  # EMPEZAR ANÁLISIS (PASO A FASE 2)
  observeEvent(input$btn_empezar, { 
    req(input$check_privacidad)
    req(global_data())         
    current_fase(2) 
  })

  # ==============================================================================
  # MODALES DE NAVEGACIÓN
  # ==============================================================================

  # NUEVO MODAL: Analysis Report (Tipo Documentación / API)
  observeEvent(input$info_analysis, {
    showModal(modalDialog(
      title = NULL, size = "xl", easyClose = TRUE, footer = NULL, class = "doc-modal",

      div(style = "position: relative; width: 100%; height: 100%; display: flex; flex-direction: column;",

          # HERO SECTION DEL MODAL
          div(class = "doc-hero",
              div(class = "doc-hero-row",
                  div(class = "doc-copy",
                      div(class = "doc-eyebrow", span(class = "eyebrow-dot"), "AuStats · Statistical Engine Documentation"),
                      h2(class = "doc-title", "Automated Table 1 Generation"),
                      p(class = "doc-sub", "Transparent, Reproducible, and Deterministic Statistical Logic")
                  ),
                  tags$button(class = "doc-btn-close", `data-bs-dismiss` = "modal", `data-dismiss` = "modal", icon("xmark"))
              )
          ),

          # CUERPO DEL MODAL (Sidebar + Contenido)
          div(class = "doc-body",

              # SIDEBAR
