# --- 2. SERVER DE LA PIEZA ---
server_tablauno <- function(input, output, session, current_fase, global_data) {

  observeEvent(input$btn_back_t1, { current_fase(1) })

  output$file_name_display_t1 <- renderUI({
    req(global_data())
    nombre_archivo <- global_data()$name
    div(style = "background-color: #f8fafc; border: 1px solid #e2e8f0; border-radius: 8px; padding: 8px; margin-bottom: 5px; width: 300px; margin-left: auto; margin-right: auto;",
        div(style = "font-size: 9px; color: #64748b; font-weight: 700; text-transform: uppercase; margin-bottom: 2px;", "Working File:"),
        div(style = "font-size: 11px; color: #1e293b; font-weight: 600; word-break: break-all; display: flex; align-items: center;",
            tags$i(class = "fa-regular fa-file-excel", style = "color: #10b981; margin-right: 6px; font-size: 13px;"), nombre_archivo)
    )
  })

  data_raw <- reactive({
    req(global_data())
    file_info <- global_data()
    if (is.data.frame(file_info$datapath)) { return(file_info$datapath) }
    ext <- tools::file_ext(file_info$name)
    tryCatch({
      if(tolower(ext) == "csv" || tolower(ext) == "txt") {
        read.csv(file_info$datapath, stringsAsFactors = FALSE)
      } else {
        read_excel(file_info$datapath)
      }
    }, error = function(e) {
      showNotification(paste("Error reading file:", e$message), type = "error")
      return(NULL)
    })
  })

  output$var_selector   <- renderUI({ req(data_raw()); div(class = "caja-grande", selectInput("vars",      label = NULL, choices = names(data_raw()),            multiple = TRUE,  width = "100%")) })
  output$group_selector <- renderUI({ req(data_raw()); div(class = "caja-normal", selectInput("group_var", label = NULL, choices = c("None", names(data_raw())), multiple = FALSE, width = "100%")) })

  output$override_median_ui <- renderUI({
    req(data_raw(), input$vars)
    vars_num <- input$vars[sapply(data_raw()[input$vars], is.numeric)]
    current_selection <- isolate(input$force_nonparam)
    valid_selection <- intersect(current_selection, vars_num)
    div(class = "caja-normal", selectInput("force_nonparam", label = NULL, choices = vars_num, selected = valid_selection, multiple = TRUE, width = "100%"))
  })

  output$override_mean_ui <- renderUI({
    req(data_raw(), input$vars)
    vars_num <- input$vars[sapply(data_raw()[input$vars], is.numeric)]
    current_selection <- isolate(input$force_param)
    valid_selection <- intersect(current_selection, vars_num)
    div(class = "caja-normal", selectInput("force_param", label = NULL, choices = vars_num, selected = valid_selection, multiple = TRUE, width = "100%"))
  })

  stats_logic <- reactive({
    req(data_raw(), input$vars)
    df <- data_raw()
    vars <- input$vars
    analysis_list <- list()
    for(v in vars) {
      if(is.numeric(df[[v]])) {
        val <- df[[v]]; n_val <- sum(!is.na(val))
        shapiro_p <- if(n_val > 3 && n_val < 5000) shapiro.test(val)$p.value else 0.05
        auto_normal <- shapiro_p > 0.05
        if (v %in% input$force_param)         { is_normal <- TRUE;  note <- " [Manual: Mean]"   }
        else if (v %in% input$force_nonparam) { is_normal <- FALSE; note <- " [Manual: Median]" }
        else                                  { is_normal <- auto_normal; note <- ""             }
        analysis_list[[v]] <- list(type = "continuous", is_normal = is_normal, shapiro = shapiro_p, note = note, data_values = val,
                                   summary_type = if(is_normal) "{mean} ({sd})" else "{median} ({p25}, {p75})",
                                   test_type    = if(is_normal) "t.test" else "wilcox.test")
      } else {
        analysis_list[[v]] <- list(type = "categorical")
      }
    }
    analysis_list
  })
  table_summary_df <- reactive({
    req(data_raw(), input$vars, stats_logic())
    df_raw <- data_raw()

    grupo_actual <- if (is.null(input$group_var) || input$group_var == "None") NULL else input$group_var
    if(!is.null(grupo_actual)) { if(length(unique(na.omit(df_raw[[grupo_actual]]))) > 20) return(NULL) }

    safe_vars <- c()
    for(v in input$vars) {
      if (!is.numeric(df_raw[[v]]) && length(unique(na.omit(df_raw[[v]]))) > 50) {
      } else { safe_vars <- c(safe_vars, v) }
    }
    if(length(safe_vars) == 0) return(NULL)

    cols_to_keep <- intersect(c(safe_vars, grupo_actual), names(df_raw))
    df   <- df_raw[, cols_to_keep, drop = FALSE]
    logic <- stats_logic()
    vars_nonnormal <- names(logic)[sapply(logic, function(x) x$type == "continuous" && !x$is_normal)]

    # Memoria para guardar si se usó Fisher o Chi-Cuadrado
    tests_usados_categoricas <- list() 

    if (is.null(grupo_actual)) {
      t1         <- CreateTableOne(vars = safe_vars, data = df)
      res_matrix <- print(t1, nonnormal = vars_nonnormal, printToggle = FALSE,
                          noSpaces = TRUE, showAllLevels = TRUE, contDigits = 1, explain = FALSE)
    } else {
      vars_fisher <- c()
      for(v in safe_vars) {
        if(logic[[v]]$type != "continuous") {
          tbl <- table(df[[v]], df[[grupo_actual]])
          usar_fisher <- FALSE
          if(any(tbl == 0) || tryCatch({ suppressWarnings({ any(chisq.test(tbl)$expected < 5) }) }, error = function(e) TRUE)) {
            usar_fisher <- TRUE
            vars_fisher <- c(vars_fisher, v)
          }
          # Guardamos usando la variable original intacta
          tests_usados_categoricas[[v]] <- if(usar_fisher) "Fisher's exact test" else "Pearson's Chi-squared test"
        }
      }
      t1 <- CreateTableOne(vars = safe_vars, strata = grupo_actual, data = df,
                           test = isTRUE(input$calc_p), addOverall = isTRUE(input$show_total))
      res_matrix <- print(t1, nonnormal = vars_nonnormal, exact = vars_fisher,
                          printToggle = FALSE, noSpaces = TRUE,
                          showAllLevels = TRUE, contDigits = 1, test = isTRUE(input$calc_p), explain = FALSE)
    }

    df_out <- as.data.frame(res_matrix)

    if("test" %in% colnames(df_out)) {
      df_out$test <- NULL
    }

    for(col in colnames(df_out)) {
      df_out[[col]] <- gsub("\\[", "(", df_out[[col]])
      df_out[[col]] <- gsub("\\]", ")", df_out[[col]])
    }

    n_row <- df_out[1, ]
    for(col in colnames(df_out)) {
      if(col != "level" && col != "p") {
        val <- trimws(n_row[[col]])
        col_clean <- ifelse(col == "Overall", "Total", col)
        new_name <- paste0(col_clean, "<br>N = ", val)
        colnames(df_out)[colnames(df_out) == col] <- new_name
      }
    }
    df_out <- df_out[-1, ] 

    rn <- rownames(df_out)
    lvl <- df_out$level
    new_df <- data.frame(matrix(ncol = ncol(df_out), nrow = 0))
    colnames(new_df) <- colnames(df_out)
    new_rn <- c()

    for (i in 1:nrow(df_out)) {
      r <- trimws(rn[i])
      l <- trimws(lvl[i])

      if (l == "") {
        new_df <- rbind(new_df, df_out[i, ])
        nombre_limpio <- ifelse(grepl("^X\\.?\\d*", r) | r == "X", "", r) 
        new_rn <- c(new_rn, nombre_limpio)
      } else {
        if (r != "" && !grepl("^X\\.?\\d*", r) && r != "X") {
          empty_row <- df_out[i, ]
          for(col in colnames(empty_row)) empty_row[1, col] <- ""
          if("p" %in% colnames(df_out)) empty_row[1, "p"] <- df_out[i, "p"] 
          new_df <- rbind(new_df, empty_row)
          new_rn <- c(new_rn, r)

          lvl_row <- df_out[i, ]
          if("p" %in% colnames(lvl_row)) lvl_row[1, "p"] <- ""
          new_df <- rbind(new_df, lvl_row)
          new_rn <- c(new_rn, paste0("&nbsp;&nbsp;&nbsp;&nbsp;", l))
        } else {
          new_df <- rbind(new_df, df_out[i, ])
          new_rn <- c(new_rn, paste0("&nbsp;&nbsp;&nbsp;&nbsp;", l))
        }
      }
    }

    df_out <- new_df
    df_out$level <- NULL

    # MAGIA HOVER DINÁMICA CON BSLIB TOOLTIP (VERSIÓN BLINDADA)
    if ("p" %in% colnames(df_out) && !is.null(grupo_actual) && isTRUE(input$calc_p)) {
      for (i in 1:nrow(df_out)) {
        pval <- trimws(df_out[i, "p"])

        if (pval != "") {
          var_name_html <- new_rn[i]

          if (!grepl("&nbsp;", var_name_html)) {
            # --- LIMPIEZA ULTRA ROBUSTA ---
            var_name_clean <- gsub("<sup>1</sup>", "", var_name_html)
            var_name_clean <- gsub("<sup>2</sup>", "", var_name_clean)
            var_name_clean <- gsub("<[^>]+>", "", var_name_clean) # Quita HTML oculto
            var_name_clean <- trimws(var_name_clean)

            test_info <- "Test not found"

            # --- EL BUSCADOR INFALIBLE ---
            # Comparamos quitando puntos, espacios, guiones y en minúsculas
            clean_str <- function(x) gsub("[^a-zA-Z0-9]", "", tolower(x))

            key_to_use <- NULL
            match_idx <- match(clean_str(var_name_clean), clean_str(names(logic)))

            if (!is.na(match_idx)) {
              key_to_use <- names(logic)[match_idx]
            }

            if (!is.null(key_to_use)) {
              if (logic[[key_to_use]]$type == "categorical") {
                # Buscamos en la memoria usando también el limpiador infalible
                match_cat_idx <- match(clean_str(key_to_use), clean_str(names(tests_usados_categoricas)))
                if (!is.na(match_cat_idx)) {
                  test_info <- tests_usados_categoricas[[names(tests_usados_categoricas)[match_cat_idx]]]
                } else {
                  test_info <- "Categorical test (Pearson/Fisher)" 
                }
              } else if (logic[[key_to_use]]$type == "continuous") {
                if (logic[[key_to_use]]$is_normal) {
                  test_info <- "Student's t-test"
                } else {
                  test_info <- "Wilcoxon rank sum test"
                }
              }
            }

            # Construimos el tooltip de bslib elegante
            test_html_content <- paste0(
              "<div style='font-size:11px; padding:3px; text-align:left;'>",
              "<b style='color:#0284c7;'>Statistical Test</b><br>", 
              test_info, 
              "</div>"
            )

            # 2. Construimos el tooltip de bslib
            tooltip_html <- as.character(
              tooltip(
                trigger = span(class="var-hover-trigger", pval),
                HTML(test_html_content), 
                placement = "right", # Lo ponemos a la izquierda para que no se salga de la pantalla
                options = list(html = TRUE)
              )
            )
            df_out[i, "p"] <- tooltip_html
          }
        }
      }
      colnames(df_out)[colnames(df_out) == "p"] <- "<i>P</i>-VALUE<sup>2</sup>"
    }

    df_final <- cbind(new_rn, df_out)
    colnames(df_final)[1] <- "CHARACTERISTIC<sup>1</sup>"
    rownames(df_final) <- NULL

    return(df_final)
  })

  # RENDERIZADO FINAL BLANCO PURO
  output$report_preview <- renderDT({
    req(table_summary_df())
    df_tabla <- table_summary_df()

    if ("level" %in% colnames(df_tabla)) {
      df_tabla <- df_tabla[, colnames(df_tabla) != "level", drop = FALSE]
    }

    # EL TRUCO: Pasamos la clase "cell-border" falsa para matar las cebras nativas de DT
    datatable(
      df_tabla,
      escape = FALSE,
      selection = "none",
      rownames = FALSE,
      class = 'row-border', # Matamos la clase 'stripe'
      options = list(
        dom = "t",
        ordering = FALSE,
        pageLength = -1,
        autoWidth = FALSE,
        # Inyectamos JS para pintar de blanco a la fuerza y sin bordes
        initComplete = JS("
          function(settings, json) {
            var api = this.api();
            $(api.table().node()).css({'background-color': 'white', 'box-shadow': 'none'});
            $(api.table().body()).find('tr, td, th').css({'background-color': 'white', 'box-shadow': 'none'});
          }
        "),
        columnDefs = list(
          list(className = "dt-left", targets = 0),
          list(className = "dt-center", targets = 1:(ncol(df_tabla)-1))
        )
      )
    ) %>%
      formatStyle(
        columns = 0:(ncol(df_tabla)-1),
        backgroundColor = 'white', # Forzamos color blanco desde R
        fontFamily = "Times New Roman",
        fontSize = "12pt"
      )
  })

  generar_mini_plots <- function(valores) {
    tmp_file <- tempfile(fileext = ".png")
    png(tmp_file, width = 1200, height = 480, bg = "white")
    par(mfrow = c(1, 2), mar = c(4, 4, 2, 1), oma = c(0,0,0,0))
    x <- na.omit(valores)
    hist(x, main = "Histogram", axes = TRUE, col = "#3498db", border = "white", breaks = 15,
         cex.main=1.5, cex.axis=1.2, cex.lab=1.4, xlab = "Value", ylab = "Frequency")
    box(col = "#bdc3c7")
    qqnorm(x, main = "Q-Q Plot", axes = TRUE, pch = 20, col = "#e74c3c", cex = 2,
           cex.main=1.5, cex.axis=1.2, cex.lab=1.4, xlab = "Theoretical", ylab = "Sample")
    qqline(x, col = "#2c3e50", lwd = 3)
    box(col = "#bdc3c7")
    dev.off()
    txt_base64 <- base64enc::dataURI(file = tmp_file, mime = "image/png")
    as.character(tags$img(src = txt_base64, style = "width: 600px; height: 240px; border-radius: 6px; display: block;"))
  }
  # --- PIE DE TABLA DINÁMICO (ESTILO APA/SCIENTIFIC) ---
  # --- PIE DE TABLA DINÁMICO (BLINDADO CONTRA NA) ---
  output$table_footnotes <- renderUI({
    req(stats_logic(), data_raw(), input$vars)

    logic <- stats_logic()
    df <- data_raw()
    grupo_actual <- if (is.null(input$group_var) || input$group_var == "None") NULL else input$group_var
    calc_p <- isTRUE(input$calc_p)

    # Función segura para comprobar grupo
    is_group_var <- function(v) { !is.null(grupo_actual) && v == grupo_actual }

    # 1. Detectar qué tipos de variables hay seleccionadas (usando isTRUE para evitar NAs)
    has_cat <- any(sapply(input$vars, function(v) isTRUE(logic[[v]]$type == "categorical") && !is_group_var(v)))
    has_norm <- any(sapply(input$vars, function(v) isTRUE(logic[[v]]$type == "continuous") && isTRUE(logic[[v]]$is_normal)))
    has_nonnorm <- any(sapply(input$vars, function(v) isTRUE(logic[[v]]$type == "continuous") && isFALSE(logic[[v]]$is_normal)))

    # Construir la primera línea (Descriptivos)
    desc_parts <- c()
    if(has_cat) desc_parts <- c(desc_parts, "n (%)")
    if(has_norm) desc_parts <- c(desc_parts, "Mean (SD)")
    if(has_nonnorm) desc_parts <- c(desc_parts, "Median (Q1, Q3)")

    foot_1 <- paste0("<sup>1</sup>", paste(desc_parts, collapse = "; "))

    # 2. Construir la segunda línea (Tests estadísticos)
    if(!is.null(grupo_actual) && calc_p) {

      has_chi <- FALSE
      has_fisher <- FALSE

      for (v in input$vars) {
        if (isTRUE(logic[[v]]$type == "categorical") && !is_group_var(v)) {
          tbl <- table(df[[v]], df[[grupo_actual]])
          usar_fisher <- FALSE

          # Cálculo seguro evitando NA en los valores esperados
          baja_frecuencia <- tryCatch({ 
            suppressWarnings({ 
              exp_vals <- chisq.test(tbl)$expected
              any(exp_vals < 5, na.rm = TRUE) 
            }) 
          }, error = function(e) TRUE)

          # Si da NA por indeterminación matemática, forzamos TRUE (Fisher) para que no explote el if
          if (is.na(baja_frecuencia)) baja_frecuencia <- TRUE

          if (any(tbl == 0) || baja_frecuencia) {
            usar_fisher <- TRUE
          }

          if (usar_fisher) {
            has_fisher <- TRUE
          } else {
            has_chi <- TRUE
          }
        }
      }

      test_parts <- c()

      if(has_chi) test_parts <- c(test_parts, "Pearson's Chi-squared test")
      if(has_fisher) test_parts <- c(test_parts, "Fisher's exact test")
      if(has_norm) test_parts <- c(test_parts, "Student's t-test")
      if(has_nonnorm) test_parts <- c(test_parts, "Wilcoxon rank sum test")

      foot_2 <- paste0("<sup>2</sup>", paste(test_parts, collapse = "; "))

      HTML(paste0(
        "<div style='font-size: 11pt; font-family: \"Times New Roman\", serif; text-align: left; margin-top: 6px; line-height: 1.5;'>",
        foot_1, "<br>", foot_2,
        "</div>"
      ))
    } else {
      HTML(paste0(
        "<div style='font-size: 11pt; font-family: \"Times New Roman\", serif; text-align: left; margin-top: 6px; line-height: 1.5;'>",
        foot_1,
        "</div>"
      ))
    }
  })

  output$normality_details <- renderUI({
    req(stats_logic(), data_raw())
    logic        <- stats_logic()
    df_raw       <- data_raw()
    grupo_actual <- if (!is.null(input$group_var) && input$group_var != "None") input$group_var else NULL
    all_vars     <- unique(c(input$vars, grupo_actual))
    items <- lapply(all_vars, function(v) {
      valores <- df_raw[[v]]; n_total <- length(valores); n_miss <- sum(is.na(valores)); p_miss <- round((n_miss / n_total) * 100, 1)
      if(n_miss == 0) {
        html_miss <- "<div style='margin-left: auto; color: #27ae60; font-size: 0.9em; font-weight: 600;'><i class='fa-solid fa-check'></i> 0% Missing</div>"
      } else if (p_miss <= 10) {
        html_miss <- paste0("<div style='margin-left: auto; color: #d97706; font-size: 0.9em; font-weight: 600; display: flex; align-items: center;'>Missing: ", n_miss, " (", p_miss, "%)<span class='missing-info-icon'>", as.character(tooltip(trigger = tags$i(class="fa-solid fa-circle-info"), HTML("<div style='font-size:11px; padding:5px;'><b style='color:#d97706;'>Listwise Deletion Applied.</b><br>As the missing rate is below 10%, rows with missing values for this variable were removed from calculations involving it. This is standard practice in reporting descriptive statistics.</div>"), placement = "right", options = list(html = TRUE))), "</span></div>")
      } else {
        html_miss <- paste0("<div style='margin-left: auto; color: #e74c3c; font-size: 0.9em; font-weight: 600; display: flex; align-items: center;'>Missing: ", n_miss, " (", p_miss, "%)<span class='missing-info-icon'>", as.character(tooltip(trigger = tags$i(class="fa-solid fa-triangle-exclamation"), HTML("<div style='font-size:11px; padding:5px;'><b style='color:#e74c3c;'>High Missing Rate!</b><br>A missing rate above 10% may compromise the statistical validity of the analysis for this specific variable. Consider using imputation methods or interpreting results with caution.</div>"), placement = "right", options = list(html = TRUE))), "</span></div>")      }
      if(v %in% names(logic) && logic[[v]]$type == "continuous") {
        info       <- logic[[v]]
        col        <- if(info$is_normal) "#2980b9" else "#d35400"
        desc_label <- if(info$is_normal) "Mean (SD)" else "Median (Q1-Q3)"
        pval_str   <- if(info$shapiro < 0.001) "< 0.001" else sprintf("%.3f", info$shapiro)
        div(style="border-bottom:1px dashed #eee; padding: 8px 0; display:flex; align-items:center; width: 100%;",
            tooltip(trigger = span(class = "var-hover-trigger", style = "font-weight: bold; cursor: help; margin-right: 5px;", v),
                    HTML(generar_mini_plots(info$data_values)), placement = "top",
                    options = list(delay = list(show = 50, hide = 100))),
            HTML(paste0(": <span style='color:", col, "; font-weight:600;'>", desc_label, "</span> ", info$note,
                        " <span style='color:#7f8c8d; font-size:0.9em; margin-left:8px;'>(Shapiro-Wilk p = ", pval_str, ")</span>")),
            HTML(html_miss))
      } else {
        label_tipo <- if(!is.null(grupo_actual) && v == grupo_actual) {
          "<span style='color: #8e44ad; font-weight: 600; margin-left: 5px;'>(Comparison Group)</span>"
        } else {
          "<span style='color: #7f8c8d; font-weight: 600; margin-left: 5px;'>(Categorical)</span>"
        }
        div(style="border-bottom:1px dashed #eee; padding: 8px 0; display:flex; align-items:center; width: 100%;",
            span(style = "font-weight: bold;", v), HTML(label_tipo), HTML(html_miss))
      }
    })
    div(tagList(items))
  })

  # --- CONEXIÓN R -> PYTHON: Enviar datos para generar textos y Word ---
  observe({
    input$regen_text # Reacciona al botón de regenerar

    # Necesitamos asegurar que tanto la lógica como la tabla final estén listas
    req(stats_logic(), input$vars, table_summary_df())

    # Convertimos la tabla de R a un dataframe plano (sin rownames como índice)
    # para que jsonlite lo pueda convertir bien a JSON.
    df_para_exportar <- table_summary_df()

    # Preparamos el paquete de datos (payload) que viajará a Python
    payload <- list(
      vars = as.list(input$vars),
      group_var = if(is.null(input$group_var) || input$group_var == "None") NULL else input$group_var,
      calc_p = isTRUE(input$calc_p),
      logic_list = stats_logic(),
      # ¡AQUÍ ESTÁ LA MAGIA! Pasamos la tabla ya calculada
      tabla_resultados = df_para_exportar 
    )

    # Disparamos la función de JavaScript (fetch_textos)
    session$sendCustomMessage("fetch_textos", payload)
  })

  # --- CONEXIÓN PYTHON -> R: Recibir textos y pintarlos ---
  output$methods_text <- renderUI({
    req(input$js_textos_result)
    HTML(paste0("<div style='text-align: justify; font-family: \"Times New Roman\", serif; font-size: 12pt; line-height: 1.5; color: #000;'>", 
                input$js_textos_result$metodologia, 
                "</div>"))
  })

  output$results_abstract <- renderUI({
    req(input$js_textos_result)
    HTML(paste0("<div style='text-align: justify; font-family: \"Times New Roman\", serif; font-size: 12pt; color: #555;'>", 
                input$js_textos_result$resultados, 
                "</div>"))
  })

  # --- DESCARGA DE WORD ---
  observeEvent(input$download_word, {
    req(table_summary_df(), stats_logic())

    # Mostrar notificación de carga
    showNotification("Generating Word Report in the cloud...", id = "word_load", duration = NULL, type = "message")

    payload <- list(
      vars = as.list(input$vars),
      group_var = if(is.null(input$group_var) || input$group_var == "None") NULL else input$group_var,
      calc_p = isTRUE(input$calc_p),
      logic_list = stats_logic(),
      tabla_resultados = table_summary_df()
    )

    # Disparamos la función de JavaScript (fetch_word)
    session$sendCustomMessage("fetch_word", payload)
  })

  # Quitar notificación cuando termine el JS
  observeEvent(input$js_word_done, {
    removeNotification(id = "word_load")
  })
}
